		Namespace(w.namespace).
		Resource("widgets").
		Name(name).
		Body(&opts).
		Do(ctx).
		Error()
}

// Example usage demonstrating the client
func ExampleUsage() {
	// Create a REST config (in real usage, this would be from kubeconfig or in-cluster config)
	config := &rest.Config{
		Host: "http://localhost:8080",
	}

	// Create the custom resource client
	client, err := NewForConfig(config)
	if err != nil {
		fmt.Println("Error creating client:", err)
		return
	}

	ctx := context.Background()

	// Get the widgets interface for a specific namespace
	widgetsClient := client.Widgets("default")

	// Create a widget
	widget := &Widget{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "example.com/v1",
			Kind:       "Widget",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name: "my-widget",
		},
		Spec: WidgetSpec{
			Size:     "large",
			Color:    "red",
			Replicas: intPtr(3),
		},
	}

	createdWidget, err := widgetsClient.Create(ctx, widget, metav1.CreateOptions{})
	if err != nil {
		fmt.Println("Error creating widget:", err)
		return
	}
	fmt.Println("Widget created:", createdWidget.Name)

	// Get a widget
	retrievedWidget, err := widgetsClient.Get(ctx, "my-widget", metav1.GetOptions{})
	if err != nil {
		fmt.Println("Error getting widget:", err)
		return
	}
	fmt.Println("Widget retrieved:", retrievedWidget.Name)

	// List widgets
	widgetList, err := widgetsClient.List(ctx, metav1.ListOptions{})
	if err != nil {
		fmt.Println("Error listing widgets:", err)
		return
	}
	fmt.Println("Widgets count:", len(widgetList.Items))

	// Delete a widget
	err = widgetsClient.Delete(ctx, "my-widget", metav1.DeleteOptions{})
	if err != nil {
		fmt.Println("Error deleting widget:", err)
		return
	}
	fmt.Println("Widget deleted")
}

// Helper function for pointer to int32
func intPtr(i int) *int32 {
	v := int32(i)
	return &v
}

